import{_ as i,o as l,c as r,ag as a}from"./chunks/framework.ePeAWSvT.js";const h=JSON.parse('{"title":"COURS : L’HYPERTENSION ARTÉRIELLE (HTA)","description":"","frontmatter":{},"headers":[],"relativePath":"matieres/sante/cours/HTA-cardio.md","filePath":"matieres/sante/cours/HTA-cardio.md"}'),t={name:"matieres/sante/cours/HTA-cardio.md"};function s(n,e,o,u,d,c){return l(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="cours-l-hypertension-arterielle-hta" tabindex="-1">COURS : L’HYPERTENSION ARTÉRIELLE (HTA) <a class="header-anchor" href="#cours-l-hypertension-arterielle-hta" aria-label="Permalink to &quot;COURS : L’HYPERTENSION ARTÉRIELLE (HTA)&quot;">​</a></h1><h2 id="_1️⃣-definition-de-l-hypertension-arterielle" tabindex="-1">1️⃣ Définition de l’hypertension artérielle <a class="header-anchor" href="#_1️⃣-definition-de-l-hypertension-arterielle" aria-label="Permalink to &quot;1️⃣ Définition de l’hypertension artérielle&quot;">​</a></h2><p>L’hypertension artérielle est une <strong>élévation persistante de la pression artérielle dans les artères</strong>.</p><p>On parle d’HTA lorsque :</p><ul><li><strong>Pression artérielle systolique ≥ 140 mmHg</strong></li><li><strong>et/ou pression artérielle diastolique ≥ 90 mmHg</strong></li></ul><p>📌 La pression artérielle correspond à la force exercée par le sang sur la paroi des artères.</p><p>Elle comprend :</p><ul><li><strong>Pression systolique</strong> : pression lors de la contraction du cœur</li><li><strong>Pression diastolique</strong> : pression lors du relâchement du cœur</li></ul><hr><h2 id="_2️⃣-types-d-hypertension" tabindex="-1">2️⃣ Types d’hypertension <a class="header-anchor" href="#_2️⃣-types-d-hypertension" aria-label="Permalink to &quot;2️⃣ Types d’hypertension&quot;">​</a></h2><h3 id="🔹-hypertension-essentielle-primaire" tabindex="-1">🔹 Hypertension essentielle (primaire) <a class="header-anchor" href="#🔹-hypertension-essentielle-primaire" aria-label="Permalink to &quot;🔹 Hypertension essentielle (primaire)&quot;">​</a></h3><ul><li>La plus fréquente (<strong>≈ 90–95 % des cas</strong>)</li><li>Cause <strong>non identifiable</strong></li><li>Résulte souvent de plusieurs facteurs :</li></ul><p>Facteurs de risque :</p><ul><li>Antécédents familiaux</li><li>Surpoids / obésité</li><li>Sédentarité</li><li>Consommation excessive de sel</li><li>Stress</li><li>Tabagisme</li><li>Âge</li></ul><hr><h3 id="🔹-hypertension-secondaire" tabindex="-1">🔹 Hypertension secondaire <a class="header-anchor" href="#🔹-hypertension-secondaire" aria-label="Permalink to &quot;🔹 Hypertension secondaire&quot;">​</a></h3><p>Elle est causée par une <strong>maladie identifiable</strong>.</p><p>Exemples :</p><ul><li>Maladies rénales</li><li>Maladies endocriniennes</li><li>Médicaments (contraceptifs, corticoïdes)</li><li>Apnée du sommeil</li></ul><hr><h2 id="_3️⃣-diagnostic-de-l-hta" tabindex="-1">3️⃣ Diagnostic de l’HTA <a class="header-anchor" href="#_3️⃣-diagnostic-de-l-hta" aria-label="Permalink to &quot;3️⃣ Diagnostic de l’HTA&quot;">​</a></h2><p>Le diagnostic repose sur <strong>plusieurs mesures de la pression artérielle</strong>.</p><p>📌 Mesure correcte :</p><ul><li>Patient au repos depuis <strong>5 minutes</strong></li><li>Position <strong>assise</strong></li><li>Bras au niveau du cœur</li></ul><p>Critères diagnostiques :</p><ul><li><strong>≥ 140/90 mmHg en consultation</strong></li><li><strong>≥ 135/85 mmHg à domicile</strong></li></ul><p>Examens complémentaires possibles :</p><ul><li>Analyse sanguine</li><li>Analyse d’urine</li><li>Électrocardiogramme (ECG)</li><li>Échographie cardiaque</li><li>Bilan rénal</li></ul><hr><h2 id="_4️⃣-symptomes-de-l-hypertension" tabindex="-1">4️⃣ Symptômes de l’hypertension <a class="header-anchor" href="#_4️⃣-symptomes-de-l-hypertension" aria-label="Permalink to &quot;4️⃣ Symptômes de l’hypertension&quot;">​</a></h2><p>⚠️ La plupart du temps <strong>l’HTA est asymptomatique</strong>.</p><p>Certains patients peuvent présenter :</p><ul><li>Céphalées (maux de tête)</li><li>Vertiges</li><li>Bourdonnements d’oreilles</li><li>Troubles visuels</li><li>Palpitations</li><li>Fatigue</li></ul><p>👉 C’est pourquoi on l’appelle souvent <strong>&quot;le tueur silencieux&quot;</strong>.</p><hr><h2 id="_5️⃣-complications-de-l-hypertension" tabindex="-1">5️⃣ Complications de l’hypertension <a class="header-anchor" href="#_5️⃣-complications-de-l-hypertension" aria-label="Permalink to &quot;5️⃣ Complications de l’hypertension&quot;">​</a></h2><p>Si elle n’est pas traitée, l’HTA peut provoquer des complications graves.</p><h3 id="🔴-complications-cardiovasculaires" tabindex="-1">🔴 Complications cardiovasculaires <a class="header-anchor" href="#🔴-complications-cardiovasculaires" aria-label="Permalink to &quot;🔴 Complications cardiovasculaires&quot;">​</a></h3><ul><li>Infarctus du myocarde</li><li>Insuffisance cardiaque</li><li>Hypertrophie ventriculaire gauche</li></ul><h3 id="🔴-complications-cerebrales" tabindex="-1">🔴 Complications cérébrales <a class="header-anchor" href="#🔴-complications-cerebrales" aria-label="Permalink to &quot;🔴 Complications cérébrales&quot;">​</a></h3><ul><li>Accident vasculaire cérébral (AVC)</li><li>Accident ischémique transitoire (AIT)</li></ul><h3 id="🔴-complications-renales" tabindex="-1">🔴 Complications rénales <a class="header-anchor" href="#🔴-complications-renales" aria-label="Permalink to &quot;🔴 Complications rénales&quot;">​</a></h3><ul><li>Insuffisance rénale chronique</li><li>Néphroangiosclérose</li></ul><h3 id="🔴-complications-oculaires" tabindex="-1">🔴 Complications oculaires <a class="header-anchor" href="#🔴-complications-oculaires" aria-label="Permalink to &quot;🔴 Complications oculaires&quot;">​</a></h3><ul><li>Rétinopathie hypertensive</li><li>Diminution de la vision</li></ul><hr><h2 id="_6️⃣-traitement-de-l-hypertension" tabindex="-1">6️⃣ Traitement de l’hypertension <a class="header-anchor" href="#_6️⃣-traitement-de-l-hypertension" aria-label="Permalink to &quot;6️⃣ Traitement de l’hypertension&quot;">​</a></h2><h3 id="🥗-mesures-hygieno-dietetiques" tabindex="-1">🥗 Mesures hygiéno-diététiques <a class="header-anchor" href="#🥗-mesures-hygieno-dietetiques" aria-label="Permalink to &quot;🥗 Mesures hygiéno-diététiques&quot;">​</a></h3><ul><li>Réduction de la consommation de <strong>sel</strong></li><li>Alimentation équilibrée</li><li>Perte de poids si nécessaire</li><li>Activité physique régulière</li><li>Réduction de l’alcool</li><li>Arrêt du tabac</li><li>Gestion du stress</li></ul><hr><h3 id="💊-traitement-medicamenteux" tabindex="-1">💊 Traitement médicamenteux <a class="header-anchor" href="#💊-traitement-medicamenteux" aria-label="Permalink to &quot;💊 Traitement médicamenteux&quot;">​</a></h3><p>Plusieurs classes de médicaments peuvent être utilisées :</p><ul><li><strong>Diurétiques</strong></li><li><strong>IEC (Inhibiteurs de l’Enzyme de Conversion)</strong></li><li><strong>ARA II (Antagonistes des récepteurs de l’angiotensine II)</strong></li><li><strong>Bêta-bloquants</strong></li><li><strong>Inhibiteurs calciques</strong></li></ul><p>📌 Le choix dépend :</p><ul><li>de l’âge</li><li>des maladies associées</li><li>du niveau de pression artérielle</li></ul><hr><h2 id="_7️⃣-surveillance-du-patient-hypertendu" tabindex="-1">7️⃣ Surveillance du patient hypertendu <a class="header-anchor" href="#_7️⃣-surveillance-du-patient-hypertendu" aria-label="Permalink to &quot;7️⃣ Surveillance du patient hypertendu&quot;">​</a></h2><p>La surveillance comprend :</p><ul><li>Mesure régulière de la <strong>pression artérielle</strong></li><li>Contrôle du <strong>poids</strong></li><li>Surveillance du <strong>bilan rénal</strong></li><li>Surveillance du <strong>bilan lipidique</strong></li><li>Suivi de l’adhésion au traitement</li></ul><hr><h2 id="_8️⃣-role-infirmier-👨‍⚕️👩‍⚕️" tabindex="-1">8️⃣ Rôle infirmier 👨‍⚕️👩‍⚕️ <a class="header-anchor" href="#_8️⃣-role-infirmier-👨‍⚕️👩‍⚕️" aria-label="Permalink to &quot;8️⃣ Rôle infirmier 👨‍⚕️👩‍⚕️&quot;">​</a></h2><p>L’infirmier joue un rôle essentiel dans la prise en charge du patient hypertendu :</p><ul><li>Mesurer correctement la <strong>pression artérielle</strong></li><li>Surveiller l’efficacité du traitement</li><li>Dépister les complications</li><li>Éduquer le patient sur l’hygiène de vie</li><li>Encourager l’adhésion au traitement</li><li>Informer sur les signes d’alerte</li></ul><p>📌 L’éducation thérapeutique permet de <strong>réduire les complications et améliorer la qualité de vie du patient</strong>.</p>',64)])])}const m=i(t,[["render",s]]);export{h as __pageData,m as default};
